package com.rotarola.portafolio_kotlin

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import di.androidModule
import di.commonModule
import org.koin.android.ext.koin.androidContext
import org.koin.core.context.startKoin
import presentation.view.atoms.theme.FeatureUITheme
import presentation.view.pages.NavigationMain

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Inicializar Koin
        startKoin {
            androidContext(this@MainActivity)
            modules(commonModule, androidModule)
        }

        setContent {
            FeatureUITheme(){
                NavigationMain() // ✅ UI compartida desde shared
            }
        }
    }
}

package com.rotarola.portafolio_kotlin

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import core.utils.AppInfo
import di.androidModule
import di.commonModule
import org.koin.android.ext.koin.androidContext
import org.koin.core.context.startKoin
import presentation.view.atoms.theme.FeatureUITheme
import presentation.view.pages.NavigationMain

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Inicializar versión de la app
        AppInfo.initialize(
            versionName = BuildConfig.VERSION_NAME,
            versionCode = BuildConfig.VERSION_CODE
        )

        // Inicializar Koin
        startKoin {
            androidContext(this@MainActivity)
            modules(commonModule, androidModule)
        }

        setContent {
            FeatureUITheme(){
                NavigationMain() // ✅ UI compartida desde shared
            }
        }
    }
}

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.compose.ui.window.ComposeUIViewController
import di.IosViewModelHolder
import di.commonModule
import di.iosModule
import org.koin.core.context.startKoin
import platform.UIKit.UIViewController
import presentation.view.atoms.theme.FeatureUITheme

fun MainViewController(): UIViewController {
    if (!IosViewModelHolder.isInitialized()) {
        val koin = startKoin {
            modules(commonModule, iosModule)
        }.koin
        IosViewModelHolder.chatBotViewModel = koin.get()
        IosViewModelHolder.authViewModel    = koin.get()
        IosViewModelHolder.menuViewModel    = koin.get()
    }

    return ComposeUIViewController {
        // TEST 4: Scaffold + OutlinedTextField
        FeatureUITheme(darkTheme = false) {
            Scaffold { padding ->
                Box(
                    modifier = Modifier.fillMaxSize().padding(padding),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(32.dp)
                    ) {
                        Text("Test TextField", style = MaterialTheme.typography.headlineMedium)
                        Spacer(Modifier.height(16.dp))

                        var text by remember { mutableStateOf("") }
                        OutlinedTextField(
                            value = text,
                            onValueChange = { text = it },
                            label = { Text("Escribe aquí") },
                            modifier = Modifier.fillMaxWidth()
                        )

                        Spacer(Modifier.height(16.dp))
                        Button(onClick = { }) { Text("OK") }
                    }
                }
            }
        }
    }
}

import androidx.compose.foundation.Image
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.layout.ContentScale
import androidx.compose.ui.unit.dp
import androidx.compose.ui.window.ComposeUIViewController
import di.IosViewModelHolder
import di.commonModule
import di.iosModule
import org.koin.core.context.startKoin
import org.jetbrains.compose.resources.painterResource
import platform.UIKit.UIViewController
import portafolio_kotlin.shared.generated.resources.Res
import portafolio_kotlin.shared.generated.resources.capibara_family_not_background
import presentation.view.atoms.theme.FeatureUITheme

fun MainViewController(): UIViewController {
    if (!IosViewModelHolder.isInitialized()) {
        val koin = startKoin {
            modules(commonModule, iosModule)
        }.koin
        IosViewModelHolder.chatBotViewModel = koin.get()
        IosViewModelHolder.authViewModel    = koin.get()
        IosViewModelHolder.menuViewModel    = koin.get()
    }

    return ComposeUIViewController {
        // TEST 5: Scaffold + TextField + Image
        FeatureUITheme(darkTheme = false) {
            Scaffold { padding ->
                Box(
                    modifier = Modifier.fillMaxSize().padding(padding),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(32.dp)
                    ) {
                        Image(
                            painter = painterResource(Res.drawable.capibara_family_not_background),
                            contentDescription = "Logo",
                            contentScale = ContentScale.Fit,
                            modifier = Modifier.size(120.dp)
                        )
                        Spacer(Modifier.height(16.dp))
                        Text("Image + TextField OK!", style = MaterialTheme.typography.headlineMedium)
                        Spacer(Modifier.height(16.dp))

                        var text by remember { mutableStateOf("") }
                        OutlinedTextField(
                            value = text,
                            onValueChange = { text = it },
                            label = { Text("Usuario") },
                            modifier = Modifier.fillMaxWidth()
                        )
                    }
                }
            }
        }
    }
}

